448→	private normalizeCondensedFeatures({
449→		condensedFeatures,
450→	}: {
451→		condensedFeatures: unknown;
452→	}): string[] | null {
453→		if (condensedFeatures === null || condensedFeatures === undefined) {
454→			return null;
455→		}
456→
457→		if (typeof condensedFeatures === 'string') {
458→			return [condensedFeatures];
459→		}
460→
461→		if (Array.isArray(condensedFeatures)) {
462→			return condensedFeatures.map(String);
463→		}
464→
465→		if (typeof condensedFeatures === 'object') {
466→			return Object.values(condensedFeatures).flatMap((value: unknown) =>
467→				Array.isArray(value) ? value.map(String) : [String(value)],
468→			);
469→		}
470→
471→		return [JSON.stringify(condensedFeatures)];
472→	}
