527→	private cleanText({ text }: { text: string | null | undefined }): string {
528→		if (!text) return '';
529→		return text
530→			.replace(/\r\n|\r|\n/g, ' ')
531→			.replace(/[*#]+\s?/g, '')
532→			.replace(/<[^>]*>/g, '')
533→			.replace(/\s{2,}/g, ' ')
534→			.trim();
535→	}
