 20→const CONV_MODEL_VERSION = '1.0.1';
 21→const CONV_MODEL_GROUP_NAME = 'conversational-search-model-group';
 22→const CONV_INGEST_PIPELINE_ID = 'products-conversational-pipeline';
 23→const CONV_SEARCH_PIPELINE_ID = 'conversational-hybrid-search-pipeline';
