 33→@Command({
 34→	name: 'bootstrap-conversational-search',
 35→	description:
 36→		'Full conversational search bootstrap: configure cluster, register models (embedding + LLM), create index, sync products',
 37→})
 38→export class BootstrapConversationalSearchCommand extends CommandRunner {
 39→	private readonly logger = new Logger(BootstrapConversationalSearchCommand.name);
 40→	private isShuttingDown = false;
 41→	private currentOperation: Promise<void> | null = null;
 42→	private isCancelled = false;
 43→
 44→	constructor(
 45→		private readonly opensearchService: OpensearchService,
 46→		private readonly opensearchConversationalService: OpensearchConversationalService,
 47→		private readonly stylesMvModel: StylesMvModel,
 48→		private readonly configService: EnvConfigService,
 49→	) {
