364→	private async processBatches({
365→		batches,
366→		concurrency,
367→		indexName,
368→		progressBar,
369→		onBatchComplete,
370→	}: {
371→		batches: { offset: number; limit: number }[];
372→		concurrency: number;
373→		indexName: string;
374→		progressBar: ProgressBar;
375→		onBatchComplete: (indexed: number, errors: number) => void;
376→	}): Promise<void> {
377→		await runWithConcurrencyLimit({
378→			items: batches,
379→			concurrency,
380→			handler: async (batch) => {
381→				if (this.isCancelled) {
382→					return { indexed: 0, errors: 0 };
383→				}
384→
385→				const styles = await this.stylesMvModel.findAll({
386→					limit: batch.limit,
387→					offset: batch.offset,
388→				});
389→
390→				if (styles.length === 0) {
391→					return { indexed: 0, errors: 0 };
392→				}
393→
394→				return this.opensearchConversationalService.bulkIndexProducts({
395→					indexName,
396→					styles,
397→				});
398→			},
399→			onItemComplete: (result) => {
400→				progressBar.increment(result.indexed + result.errors);
401→				onBatchComplete(result.indexed, result.errors);
402→			},
403→			onItemError: (error) => {
404→				this.logger.error(`Batch processing error: ${(error as Error).message}`);
405→			},
406→		});
407→	}
408→
409→	@Option({
410→		flags: '-f, --model-format <modelFormat>',
411→		description: 'Model format: TORCH_SCRIPT or ONNX (default: TORCH_SCRIPT)',
412→	})
413→	parseModelFormat(value: string): string {
414→		const valid = ['TORCH_SCRIPT', 'ONNX'];
415→		if (!valid.includes(value)) {
416→			throw new Error(`Model format must be one of: ${valid.join(', ')}`);
417→		}
418→		return value;
419→	}
420→
421→	@Option({
422→		flags: '-b, --batch-size <batchSize>',
423→		description: 'Products per batch (default: 60)',
424→	})
425→	parseBatchSize(value: string): number {
426→		const size = parseInt(value, 10);
427→		if (isNaN(size) || size < 1 || size > 1000) {
428→			throw new Error('Batch size must be between 1 and 1000');
429→		}
430→		return size;
431→	}
432→
433→	@Option({
434→		flags: '-c, --concurrency <concurrency>',
435→		description: 'Concurrent batch operations (default: 2)',
436→	})
437→	parseConcurrency(value: string): number {
438→		const conc = parseInt(value, 10);
439→		if (isNaN(conc) || conc < 1 || conc > 20) {
440→			throw new Error('Concurrency must be between 1 and 20');
441→		}
442→		return conc;
443→	}
444→
445→	@Option({
446→		flags: '--cleanup',
447→		description:
448→			'Delete existing conversational index, pipelines, and models before bootstrapping',
449→	})
450→	parseCleanup(): boolean {
451→		return true;
452→	}
