  1→import { Inject, Injectable, Logger } from '@nestjs/common';
  2→import { Redis } from 'ioredis';
  3→import Keyv from 'keyv';
  4→import Redlock, { Lock } from 'redlock';
  5→
  6→import {
  7→	REDIS_WRITE_CLIENT,
  8→	REDIS_READ_CLIENT,
  9→	CACHE_WRITE_MANAGER,
 10→	CACHE_READ_MANAGER,
 11→} from '@constants/common.constant';
 12→
 13→import { Namespaces } from '@interfaces/cache.interface';
 14→
 15→import { LogExecution } from '@decorators/log-execution.decorator';
 16→
 17→export enum ConsistencyLevel {
 18→	EVENTUAL = 'eventual',
 19→	STRONG = 'strong',
 20→}
 21→
 22→export interface CacheError extends Error {
 23→	code: 'CONNECTION_FAILED' | 'KEY_NOT_FOUND' | 'OPERATION_FAILED';
 24→	originalError?: Error;
 25→}
 26→
 27→@Injectable()
 28→export class CacheService {
 29→	private readonly logger = new Logger(CacheService.name);
 30→	private readonly redlock: Redlock;
 31→	private readonly redisWriteClient: Redis;
 32→	private readonly redisReadClient: Redis;
 33→	private readonly cacheWriteManager: Keyv;
 34→	private readonly cacheReadManager: Keyv;
 35→	private readonly recentWrites = new Map<string, number>();
 36→	private readonly CONSISTENCY_WINDOW_MS = 1000;
 37→	private isReadReplicaHealthy = true;
 38→
 39→	constructor(
 40→		@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
 41→		@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
 42→		@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
 43→		@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
 44→	) {
 45→		this.cacheWriteManager = cacheWriteManager;
 46→		this.cacheReadManager = cacheReadManager;
 47→		this.redisWriteClient = redisWriteClient;
 48→		this.redisReadClient = redisReadClient;
 49→		this.redlock = new Redlock([redisWriteClient], {
 50→			driftFactor: 0.01,
 51→			retryCount: 10,
 52→			retryDelay: 200,
 53→			retryJitter: 200,
 54→		});
 55→
 56→		this.setupHealthChecks();
 57→		this.startRecentWritesCleanup();
 58→	}
 59→
 60→	@LogExecution({
 61→		paramFormatter: (params) => params,
 62→		responseFormatter: () => '',
 63→	})
 64→	async get<T>({
 65→		namespace,
 66→		key,
 67→		consistency = ConsistencyLevel.EVENTUAL,
 68→	}: {
 69→		namespace: Namespaces;
 70→		key: string;
 71→		consistency?: ConsistencyLevel;
 72→	}): Promise<T | null> {
 73→		const namespacedKey = this.getNamespacedKey({ namespace, key });
 74→
 75→		const shouldReadFromMaster = this.shouldReadFromMaster(namespacedKey, consistency);
 76→		const cacheManager = shouldReadFromMaster
 77→			? this.cacheWriteManager
 78→			: this.cacheReadManager;
 79→		const source = shouldReadFromMaster ? 'master' : 'replica';
 80→
 81→		try {
 82→			const result = (await cacheManager.get(namespacedKey)) as T;
 83→
 84→			if (!result) {
 85→				this.logger.log('Cache miss', { namespace, key, consistency, source });
 86→				return null;
 87→			}
 88→
 89→			this.logger.log('Cache hit', { namespace, key });
 90→
 91→			return result;
 92→		} catch (error) {
 93→			const e = error as Error;
 94→			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
 95→
 96→			if (!shouldReadFromMaster && this.isReadReplicaHealthy) {
 97→				this.logger.warn('Read replica failed, falling back to master', {
 98→					namespace,
 99→					key,
100→				});
101→				this.isReadReplicaHealthy = false;
102→				return this.get({ namespace, key, consistency: ConsistencyLevel.STRONG });
103→			}
104→
105→			throw this.createCacheError('CONNECTION_FAILED', e);
106→		}
107→	}
108→
109→	@LogExecution({
110→		paramFormatter: (params: {
111→			namespace: Namespaces;
112→			key: string;
113→			value: unknown;
114→			ttl?: number;
115→		}) => ({
116→			namespace: params.namespace,
117→			key: params.key,
118→			value: '***',
119→			ttl: params.ttl,
120→		}),
121→		responseFormatter: () => '',
122→	})
123→	// eslint-disable-next-line @typescript-eslint/no-unnecessary-type-parameters
124→	async set<T>({
125→		namespace,
126→		key,
127→		value,
128→		ttl,
129→	}: {
130→		namespace: Namespaces;
131→		key: string;
132→		value: T;
133→		ttl?: number;
134→	}): Promise<void> {
135→		const namespacedKey = this.getNamespacedKey({ namespace, key });
136→
137→		try {
138→			await this.cacheWriteManager.set(namespacedKey, value, ttl);
139→			this.trackRecentWrite(namespacedKey);
140→			this.logger.log('Cached value', { namespace, key, ttl });
141→		} catch (error) {
142→			const e = error as Error;
143→			this.logger.error(`Error setting cache: ${e.message}`, e.stack);
144→			throw this.createCacheError('OPERATION_FAILED', e);
145→		}
146→	}
147→
148→	@LogExecution({
149→		paramFormatter: (params) => params,
150→		responseFormatter: (res) => (res ? 'true' : 'false'),
151→	})
152→	async has({
153→		namespace,
154→		key,
155→	}: {
156→		namespace: Namespaces;
157→		key: string;
158→	}): Promise<boolean> {
159→		this.logger.log('Checking cache key existence', { namespace, key });
160→		const value = await this.get<unknown>({ namespace, key });
161→		return value !== null;
162→	}
163→
164→	@LogExecution({
165→		paramFormatter: (params) => params,
166→		responseFormatter: (res) => (res ? 'true' : 'false'),
167→	})
168→	async deleteOne({
169→		namespace,
170→		key,
171→	}: {
172→		namespace: Namespaces;
173→		key: string;
174→	}): Promise<boolean> {
175→		try {
176→			const namespacedKey = this.getNamespacedKey({ namespace, key });
177→			await this.cacheWriteManager.delete(namespacedKey);
178→			this.logger.log('Deleted cache key', { namespace, key });
179→			return true;
180→		} catch (error) {
181→			const e = error as Error;
182→			this.logger.error(`Error deleting from cache: ${e.message}`, e.stack);
183→			return false;
184→		}
185→	}
186→
187→	async incrementByOne({
188→		namespace,
189→		key,
190→	}: {
191→		namespace: Namespaces;
192→		key: string;
193→	}): Promise<void> {
194→		try {
195→			const namespacedKey = this.getNamespacedKey({ namespace, key });
196→			await this.redisWriteClient.incr(namespacedKey);
197→		} catch (error) {
198→			const e = error as Error;
199→			this.logger.error(`Error incrementing cache key: ${e.message}`, e.stack, {
200→				namespace,
201→				key,
202→			});
203→			throw error;
204→		}
205→	}
206→
207→	async deleteAll(): Promise<boolean> {
208→		try {
209→			await this.cacheWriteManager.clear();
210→
211→			await new Promise((resolve) => setTimeout(resolve, 100));
212→
213→			await this.cacheReadManager.clear();
214→			this.recentWrites.clear();
215→			this.logger.log('Cleared all cache');
216→			return true;
217→		} catch (error) {
218→			const e = error as Error;
219→			this.logger.error(`Error clearing cache: ${e.message}`, e.stack);
220→			return false;
221→		}
222→	}
223→
224→	async withLock<T>({
225→		lockKey,
226→		operation,
227→		ttl = 5000,
228→	}: {
229→		lockKey: string;
230→		operation: () => Promise<T>;
231→		ttl?: number;
232→	}): Promise<T> {
233→		this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
234→		const lock = await this.redlock.acquire([lockKey], ttl);
235→
236→		try {
237→			return await operation();
238→		} finally {
239→			this.logger.log('Releasing lock', { lockKey });
240→			await lock.release();
241→		}
242→	}
243→
244→	async acquireLock({
245→		lockKey,
246→		ttl = 5000,
247→	}: {
248→		lockKey: string;
249→		ttl: number;
250→	}): Promise<Lock> {
251→		try {
252→			this.logger.log('Acquiring lock', { lockKey, ttlMs: ttl });
253→			return await this.redlock.acquire([lockKey], ttl);
254→		} catch (error) {
255→			this.logger.error(`Failed to acquire lock: ${error}`);
256→			throw error;
257→		}
258→	}
259→
260→	async releaseLock({ lock }: { lock: Lock }): Promise<void> {
261→		try {
262→			this.logger.log('Releasing lock', { lockKey: lock.resources.join(',') });
263→			await lock.release();
264→		} catch (error) {
265→			this.logger.error(`Failed to release lock: ${error}`);
266→			throw error;
267→		}
268→	}
269→
270→	private getNamespacedKey({
271→		namespace,
272→		key,
273→	}: {
274→		namespace: Namespaces;
275→		key: string;
276→	}): string {
277→		return `${namespace}:${key}`;
278→	}
279→
280→	private shouldReadFromMaster(key: string, consistency: ConsistencyLevel): boolean {
281→		if (consistency === ConsistencyLevel.STRONG) {
282→			return true;
283→		}
284→
285→		if (!this.isReadReplicaHealthy) {
286→			return true;
287→		}
288→
289→		const lastWriteTime = this.recentWrites.get(key);
290→		if (lastWriteTime) {
291→			const timeSinceWrite = Date.now() - lastWriteTime;
292→			return timeSinceWrite < this.CONSISTENCY_WINDOW_MS;
293→		}
294→
295→		return false;
296→	}
297→
298→	private trackRecentWrite(key: string): void {
299→		this.recentWrites.set(key, Date.now());
300→	}
301→
302→	private startRecentWritesCleanup(): void {
303→		setInterval(() => {
304→			const now = Date.now();
305→			for (const [key, timestamp] of this.recentWrites.entries()) {
306→				if (now - timestamp > this.CONSISTENCY_WINDOW_MS * 2) {
307→					this.recentWrites.delete(key);
308→				}
309→			}
310→		}, this.CONSISTENCY_WINDOW_MS).unref();
311→	}
312→
313→	private setupHealthChecks(): void {
314→		this.redisReadClient.on('error', (error) => {
315→			this.logger.error('Read replica connection error:', error);
316→			this.isReadReplicaHealthy = false;
317→		});
318→
319→		this.redisReadClient.on('ready', () => {
320→			this.logger.log('Read replica connection restored');
321→			this.isReadReplicaHealthy = true;
322→		});
323→
324→		this.redisWriteClient.on('error', (error) => {
325→			this.logger.error('Write client connection error:', error);
326→		});
327→	}
328→
329→	private createCacheError(code: CacheError['code'], originalError?: Error): CacheError {
330→		const error = new Error(`Cache operation failed: ${code}`) as CacheError;
331→		error.code = code;
332→		if (originalError) {
333→			error.originalError = originalError;
334→		}
335→		return error;
336→	}
337→}
