159→	const logger = Logger;
160→	const validatedConfig = plainToInstance(EnvironmentVariables, config, {
161→		enableImplicitConversion: true,
162→	});
163→
164→	const errors = validateSync(validatedConfig, {
165→		skipMissingProperties: false,
166→		forbidUnknownValues: true,
167→		stopAtFirstError: true,
168→		forbidNonWhitelisted: true,
169→	});
170→
171→	if (errors.length > 0) {
172→		logger.error('Config validation error', errors);
173→		throw new Error(errors.toString());
174→	}
175→
176→	return validatedConfig;
